import { ActionPageContentBlock } from '@domain/actionPages';
import { PublicActionPage } from '@domain/publicActionPage';
import { getStaticPath } from '@utils/getStaticPath/getStaticPath';
import DOMPurify from 'dompurify';
import { CSSProperties } from 'react';
import { useTranslation } from 'react-i18next';
import { Image } from 'src/builder/PublicActionPage/components/Image';
import { Link } from 'src/builder/PublicActionPage/components/Link';
import { Paragraph } from 'src/builder/PublicActionPage/components/Paragraph';

export const ActionPageFooter = ({
  actionPage,
  isEmbedded = false,
}: {
  actionPage?: PublicActionPage;
  isEmbedded?: boolean;
}) => {
  const { t } = useTranslation('actionPagesBuilder');

  if (!actionPage) {
    return null;
  }

  const { designConfiguration, footerDisclaimer, footerShowAccountName } = actionPage;

  const { footerBackgroundColor } = designConfiguration;

  const footerBlock: ActionPageContentBlock = {
    content: {
      backgroundColor: footerBackgroundColor,
      disclaimer: footerDisclaimer,
      showAccountName: footerShowAccountName,
    },
    type: 'footer',
  };

  const { fundConfiguration } = actionPage;
  const { fundSelectionsAttributes } = fundConfiguration || {};

  const disclaimers = (fundSelectionsAttributes ?? [])
    .sort((a, b) => (a?.position ?? 0) - (b?.position ?? 0))
    .map(
      (fund) =>
        fund?.fund?.translationsAttributes?.find(
          (transAttrs) => transAttrs?.languageIsoCode === 'en'
        )?.disclaimer
    )
    .filter((disclaimer) => typeof disclaimer === 'string') as string[];

  return (
    <footer
      className="z-[1] mt-auto flex w-full justify-center bg-neutral-100"
      style={{
        backgroundColor: footerBlock.content.backgroundColor,
      }}
    >
      <div
        className="flex w-full max-w-[960px] flex-col items-center justify-center gap-5 p-8 text-center"
        id="preview-block-footer-trigger"
        style={
          {
            backgroundColor: designConfiguration.footerBackgroundColor,
          } as CSSProperties
        }
      >
        {footerBlock.content.disclaimer && (
          <Paragraph
            dangerouslySetInnerHTML={{
              __html: DOMPurify.sanitize(footerBlock.content.disclaimer),
            }}
          />
        )}
        {disclaimers?.map((d) => (
          <Paragraph
            className="w-full list-inside"
            dangerouslySetInnerHTML={{
              __html: DOMPurify.sanitize(d),
            }}
            key={`fund-disclaimer-${d}`}
          />
        ))}
        {!isEmbedded && (
          <>
            <Paragraph>
              {t('previewBlock.footer.copyright', {
                interpolation: { escapeValue: false },
                withAccountName: footerBlock.content.showAccountName
                  ? `${actionPage.account.displayName} and `
                  : '',
                year: new Date().getFullYear(),
              })}
            </Paragraph>
            <Link
              className="!ml-0"
              href="https://anedot.com"
              rel="noopener noreferrer"
              target="_blank"
            >
              <Image
                alt="anedot typemark"
                className="w-[73px]"
                src={`${getStaticPath()}images/anedot_typemark_light.svg`}
              />
            </Link>
          </>
        )}
      </div>
    </footer>
  );
};

